import { useEffect, useRef } from 'react'
import { io, Socket } from 'socket.io-client'
import { useAuthStore } from '../store/authStore'
import { useMarketDataStore } from '../store/marketDataStore'
import { usePortfolioStore } from '../store/portfolioStore'
import { MarketFeedData, Quote } from '../types'
import toast from 'react-hot-toast'

const WS_URL = import.meta.env.VITE_WS_URL || 'ws://localhost:8000'

export const useWebSocket = () => {
  const socketRef = useRef<Socket | null>(null)
  const { token, user } = useAuthStore()
  const { updateQuote, updateMarketFeed } = useMarketDataStore()
  const { updatePosition, fetchPortfolio } = usePortfolioStore()

  useEffect(() => {
    if (!token || !user) {
      // Disconnect if not authenticated
      if (socketRef.current) {
        socketRef.current.disconnect()
        socketRef.current = null
      }
      return
    }

    // Create WebSocket connection
    const socket = io(WS_URL, {
      auth: {
        token,
      },
      transports: ['websocket'],
    })

    socketRef.current = socket

    // Connection events
    socket.on('connect', () => {
      console.log('WebSocket connected')
      toast.success('Real-time data connected', { duration: 2000 })
    })

    socket.on('disconnect', (reason) => {
      console.log('WebSocket disconnected:', reason)
      if (reason === 'io server disconnect') {
        // Server initiated disconnect, try to reconnect
        socket.connect()
      }
    })

    socket.on('connect_error', (error) => {
      console.error('WebSocket connection error:', error)
      toast.error('Connection error. Retrying...', { duration: 3000 })
    })

    // Market data events
    socket.on('quote_update', (data: Quote) => {
      updateQuote(data)
    })

    socket.on('market_feed', (data: MarketFeedData) => {
      updateMarketFeed(data)
    })

    // Trading events
    socket.on('order_update', (data: any) => {
      toast.success(`Order ${data.status}: ${data.symbol}`, { duration: 3000 })
      // Refresh portfolio after order update
      fetchPortfolio()
    })

    socket.on('position_update', (data: any) => {
      updatePosition(data)
    })

    socket.on('portfolio_update', () => {
      fetchPortfolio()
    })

    // AI Trading events
    socket.on('ai_signal', (data: any) => {
      toast(`AI Signal: ${data.signal_type} ${data.symbol}`, {
        duration: 5000,
        icon: '🤖',
      })
    })

    socket.on('ai_trade_executed', (data: any) => {
      toast.success(`AI Trade: ${data.transaction_type} ${data.symbol}`, {
        duration: 4000,
        icon: '🤖',
      })
      fetchPortfolio()
    })

    // Error events
    socket.on('error', (error: any) => {
      console.error('WebSocket error:', error)
      toast.error(error.message || 'WebSocket error')
    })

    // Alert events
    socket.on('alert', (data: any) => {
      toast(data.message, {
        duration: 4000,
        icon: data.type === 'warning' ? '⚠️' : 'ℹ️',
      })
    })

    // Cleanup on unmount
    return () => {
      if (socketRef.current) {
        socketRef.current.disconnect()
        socketRef.current = null
      }
    }
  }, [token, user, updateQuote, updateMarketFeed, updatePosition, fetchPortfolio])

  // Subscribe to market data for specific symbols
  const subscribeToQuotes = (symbols: string[]) => {
    if (socketRef.current && socketRef.current.connected) {
      socketRef.current.emit('subscribe_quotes', { symbols })
    }
  }

  // Unsubscribe from market data
  const unsubscribeFromQuotes = (symbols: string[]) => {
    if (socketRef.current && socketRef.current.connected) {
      socketRef.current.emit('unsubscribe_quotes', { symbols })
    }
  }

  // Subscribe to AI signals
  const subscribeToAISignals = () => {
    if (socketRef.current && socketRef.current.connected) {
      socketRef.current.emit('subscribe_ai_signals')
    }
  }

  // Send custom message
  const sendMessage = (event: string, data: any) => {
    if (socketRef.current && socketRef.current.connected) {
      socketRef.current.emit(event, data)
    }
  }

  return {
    socket: socketRef.current,
    isConnected: socketRef.current?.connected || false,
    subscribeToQuotes,
    unsubscribeFromQuotes,
    subscribeToAISignals,
    sendMessage,
  }
}
